head.script:
//-------------------------------------------------------------------------
// 전역변수
//-------------------------------------------------------------------------
scwin.vCurDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.vtrDt = $c.date.addDate(scwin.vCurDate, -7);


scwin.param = "";

scwin.flag = "";	
scwin.selPchLodeptCd = "";
scwin.qryConDt = "";
scwin.qryConLastDt = "";
scwin.acctCd = "";
scwin.acctNm = "";
scwin.strcopCoClntNo = "";
scwin.strcopCoClntNm = "";
scwin.strlobranCd = "";
scwin.strlobranNm = "";
scwin.olddata = "";
scwin.oldCol = "";

//-------------------------------------------------------------------------
// 화면 로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    scwin.param = $c.data.getParameter();

    scwin.flag = scwin.param.flag ==  null ? "" :scwin.param.flag;	
    scwin.selPchLodeptCd = scwin.param.selPchLodeptCd ==  null ? "" :scwin.param.selPchLodeptCd;
    scwin.qryConDt = scwin.param.qryConDt ==  null ? "" :scwin.param.qryConDt;
    scwin.qryConLastDt = scwin.param.qryConLastDt ==  null ? "" :scwin.param.qryConLastDt;
    scwin.acctCd = scwin.param.acctCd ==  null ? "" :scwin.param.acctCd;
    scwin.acctNm = scwin.param.acctNm ==  null ? "" :scwin.param.acctNm;
    scwin.strcopCoClntNo = scwin.param.copCoClntNo ==  null ? "" :scwin.param.copCoClntNo;
    scwin.strcopCoClntNm = scwin.param.copCoClntNm ==  null ? "" :scwin.param.copCoClntNm;
    scwin.strlobranCd = scwin.param.strlobranCd ==  null ? "" :scwin.param.strlobranCd;
    scwin.strlobranNm = scwin.param.strlobranNm ==  null ? "" :scwin.param.strlobranNm;

    //공통코드데이터 호출   
    const codeOptions = [
        { grpCd: "FS500", compID: "gr_pchsInfo:dcsnClsCd"}, // 셀렉트
        { grpCd: "FS250", compID: "gr_pchsInfo:pchsGoodsPatternCd"}, // 셀렉트
        { grpCd: "SD180", compID: "acb_pchsMainMainPattern, gr_pchsInfo:pchsMainMainPattern"}, // 셀렉트
        // { grpCd: "OP117", compID: "acb_inqShift" } // 셀렉트
        // { grpCd: "LoBranEBC","retriveLoBranUpperList", compID: "lc_lobranCd" } // 셀렉트
    ];
    $c.data.setCommonCode(codeOptions);	

    const param = [
        {
            method: "getGridComboByUpperCd",
            param1: "LO102",
            param2: "01",
            param3: false,
            compID: "gr_pchsInfo:qtyUnit"
        },
        {
            method: "getGridComboByUpperCd",
            param1: "LO102",
            param2: "02",
            param3: false,
            compID: "gr_pchsInfo:wtUnit"
        },
        // {
        //     method: "getGridComboByUpperCd",
        //     param1: "SD180",
        //     param2: "",
        //     param3: false,
        //     compID: "gr_pchsInfo:pchsMainMainPattern"
        // },
    ];
    $c.data.setGauceUtil(param);




    rd_transCargoClsCd.setValue("");


};

scwin.ondataload = function() {
    acb_pchsMainMainPattern.setValue("");

}

//-------------------------------------------------------------------------
// UDC 기본 날짜 세팅
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    ica_rsltsDt.setInitDate(scwin.vtrDt, scwin.vCurDate);

}

//-------------------------------------------------------------------------
// Default Data Setting / f_setDefalutData()
//-------------------------------------------------------------------------
scwin.btn_init_onClick = function (e) {
    scwin.udcOnCompleted();

    ed_pchsDeptCd.focus();

};

//-------------------------------------------------------------------------
// 대문자 변환
//-------------------------------------------------------------------------
scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

//-------------------------------------------------------------------------
// 그리드 Decode
//-------------------------------------------------------------------------
scwin.decode_adjmTrgtYn = function(data){
    return $c.gus.decode(data, 
        "1", "Y",
        "0", "N", ""
    );
};

//-------------------------------------------------------------------------
// 그리드 Decode
//-------------------------------------------------------------------------
scwin.decode_stndPcostYn = function(data){
    return $c.gus.decode(data, 
        "1", "Y",
        "0", "N", ""
    );
};

//-------------------------------------------------------------------------
// 그리드 Decode
//-------------------------------------------------------------------------
scwin.stndPcostYn_decode = function(data) {
    return $c.gus.decode(data, 
    "1", "Y",
    "0", "N", ""
);  
}

//-------------------------------------------------------------------------
// 거래처별 통합 매입 조회 / f_Retrieve()
//-------------------------------------------------------------------------
scwin.btn_retrieve_onClick = async function (e) {

    // 검색조건 필수 입력 체크, 동일 날짜 포함 여부 체크
    if (! await $c.gus.cfValidate([ed_pchsDeptCd])) {
        return;
    }

    if(await ica_rsltsDtSt.getValue() > ica_rsltsDtEnd.getValue()) {
        await $c.win.alert("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
        ica_rsltsDtSt.focus();
        return;
    }


    dma_queryConditionDTO.set("pchsDeptCd", ed_pchsDeptCd.getValue());
    dma_queryConditionDTO.set("rsltsDtSt", ica_rsltsDtSt .getValue());
    dma_queryConditionDTO.set("rsltsDtEnd", ica_rsltsDtEnd.getValue());
    dma_queryConditionDTO.set("odrNo", ed_odrNo.getValue());
    dma_queryConditionDTO.set("bilgClntNo", ed_bilgClntNo.getValue());
    dma_queryConditionDTO.set("cargoClsCd", rd_transCargoClsCd.getValue());

    $c.sbm.execute(sbm_queryConditionDTO);


};

//-------------------------------------------------------------------------
// 거래처별 통합 매입 그리드 더블클릭시
//-------------------------------------------------------------------------
scwin.gr_order_onDblClick = function (rowIndex, columnIndex, columnId) {
    dma_queryConditionDTO.set("odrNo", ds_ord.getCellData(rowIndex, "odrNo"));
    dma_queryConditionDTO.set("blNoYn", "0");

    $c.sbm.execute(sbm_queryConditionDTODtl);

};

//-------------------------------------------------------------------------
// 오더별 매입 현황 로드시
//-------------------------------------------------------------------------
scwin.ord_submitDone = function (e) {
    if(ds_ord.getTotalRow() == 0) {
        $c.win.alert(MSG_CM_ERR_003);
    }

    spa_totalRow.setValue(ds_ord.getTotalRow());

};


//-------------------------------------------------------------------------
// 매입관리 로드시
//-------------------------------------------------------------------------
scwin.pchsInfo_submitDone = function (e) {
    spa_totalRow2.setValue(ds_pchsInfo.getTotalRow());


};

//-------------------------------------------------------------------------
// UDC 공통 팝업 (매입부서)
//-------------------------------------------------------------------------
scwin.udc_pchsDept_onClick = async function (e) {

    udc_pchsDept.cfCommonPopUp(scwin.udc_pchsDept_callBackFunc
    , ed_pchsDeptCd.getValue()
    ,ed_pchsDeptNm.getValue()
    ,"F"
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,"F"
    ,null);
};


scwin.udc_pchsDept_onblurCode = async function (e) {
    if(ed_pchsDeptCd.getValue() != "") {
        udc_pchsDept.cfCommonPopUp(scwin.udc_pchsDept_callBackFunc, ed_pchsDeptCd.getValue() ,"","T",null,null,null,null,null,null,null,null,null,null,null,null,null);
    }else {
        return;
    }
};

scwin.udc_pchsDept_onChangeName = async function (info) {
    if(ed_pchsDeptNm.getValue() != "") {
        udc_pchsDept.cfCommonPopUp(scwin.udc_pchsDept_callBackFunc, "",ed_pchsDeptNm.getValue(),"T",null,null,null,null,null,null,null,null,null,null,null,null,null);
    } else {
        return;
    }
};

//-------------------------------------------------------------------------
// UDC 공통 팝업 콜백(매입부서)
//-------------------------------------------------------------------------
scwin.udc_pchsDept_callBackFunc = function(ret) {
    if(ret != null) {
        $c.gus.cfSetReturnValue(ret, ed_pchsDeptCd, ed_pchsDeptNm)
    }
}

//-------------------------------------------------------------------------
// UDC 공통 팝업 (청구거래처)
//-------------------------------------------------------------------------
scwin.udc_bilgClnt_onClick = async function (e) {

    udc_bilgClnt.cfCommonPopUp(scwin.udc_bilgClnt_callBackFunc
    , ed_bilgClntNo.getValue()
    ,ed_bilgClntNm.getValue()
    ,"F"
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null);
};


scwin.udc_bilgClnt_onblurCode = async function (e) {
    if(ed_bilgClntNo.getValue() != "") {
        udc_bilgClnt.cfCommonPopUp(scwin.udc_bilgClnt_callBackFunc, ed_bilgClntNo.getValue() ,"","T",null,null,null,null,null,null,null,null,null,null,null,null,null);
    }else {
        return;
    }
};

scwin.udc_bilgClnt_onChangeName = async function (info) {
    if(ed_bilgClntNm.getValue() != "") {
        udc_bilgClnt.cfCommonPopUp(scwin.udc_bilgClnt_callBackFunc, "",ed_bilgClntNm.getValue(),"T",null,null,null,null,null,null,null,null,null,null,null,null,null);
    } else {
        return;
    }
};

//-------------------------------------------------------------------------
// UDC 공통 팝업 콜백(청구거래처)
//-------------------------------------------------------------------------
scwin.udc_bilgClnt_callBackFunc = function(ret) {
    if(ret != null) {
        $c.gus.cfSetReturnValue(ret, ed_bilgClntNo, ed_bilgClntNm)
    }
}

//-------------------------------------------------------------------------
// 그리드 편집
//-------------------------------------------------------------------------
scwin.gr_onkeyup = function(info) {

    if(info.newValue == "") {
        return;
    }

    // if(info.oldValue == info.newValue) {
    //     return;
    // }


    if(info.keyCode == "13") {
        scwin.gr_master_openPopup(info.rowIndex, info.colIndex);
    }




}

//-------------------------------------------------------------------------
// Grid 공통팝업 pchsClntNm, vehclNo
//-------------------------------------------------------------------------
scwin.gr_master_openPopup = function(rowIndex, columnIndex) {
    let colid = gr_orderEachUnityPurchaseList.getColumnID(columnIndex);


    switch(colid) {
        // 청구처
        case "pchsClntNm" : 
            if (ds_ord.getCellData(rowIndex, "dcsnClsCd") != "1"  ){
                $c.win.alert("확정구분이 미확인 상태만 수정할 수 있습니다.");
                return false;
            }

            scwin.f_openCommonPopUpGrid(1, rowIndex, ds_ord.getCellData(rowIndex, "pchsClntNo"), ds_ord.getCellData(rowIndex, "pchsClntNm"), "F", "F")
        break
        // 차량번호
        case "vehclNo" : 
            scwin.f_openCommonPopUpGrid(2, rowIndex, "", ds_ord.getCellData(rowIndex, "vehclNo"), "F", "F")

        break

        default :  
        break;
    }
}


//-------------------------------------------------------------------------
// Grid 공통팝업 컬럼ID pchsClntNm, vehclNo
//-------------------------------------------------------------------------
scwin.f_openCommonPopUpGrid = async function(disGubun, row, pCode, pName, pClose, pAllSearch) {

    switch(disGubun) {
        case 1 :

            ds_ord.setCellData(row, "pchsClntNo", "");
            ds_ord.setCellData(row, "pchsClntNm", "");
            udc_comCode_Grid.setSelectId("retrieveClntInfo");
            udc_comCode_Grid.cfCommonPopUp(scwin.udc_gridPopup_CallbackFunc1
                                        , pCode
                                        , pName
                                        , pClose
                                        , null
                                        , null
                                        , null
                                        , "3,4,5,6,7,8,9,10"
                                        , null
                                        , null
                                        , null
                                        , null
                                        , null
                                        , null
                                        , "F"
                                        , null
                                        , "매입거래처 코드,매입거래처,종류");
        break;

        case 2 :
            ds_ord.setCellData(row, "vehclNo", "");

            ds_ord.setCellData(row, "eqCd", "");
            ds_ord.setCellData(row, "copCoClntNo", "");
            ds_ord.setCellData(row, "copCoClntNm", "");
            ds_ord.setCellData(row, "pchsClntNo", "");
            ds_ord.setCellData(row, "pchsClntNm", "");

            udc_comCode_Grid.setSelectId("retrieveVehclList");
            udc_comCode_Grid.cfCommonPopUp(scwin.udc_gridPopup_CallbackFunc2
                                        , ""
                                        , ""
                                        , pClose
                                        , null
                                        , null
                                        , null
                                        , null
                                        , null
                                        , null
                                        , null
                                        , null
                                        , null
                                        , null
                                        , "F"
                                        , "차량조회,차량번호,차량종류"
                                        );
        break;
    default :
    break;
    }
};

//-------------------------------------------------------------------------
// Grid 공통팝업 Callback 컬럼ID(pchsClntNm, vehclNo)
//-------------------------------------------------------------------------
scwin.udc_gridPopup_CallbackFunc1 = function(ret) {
    let rowIdx = gr_orderEachUnityPurchaseList.getFocusedRowIndex();
    if(ret != null && ret[0] != "N/A") {
        ds_ord.setCellData(rowIdx, "pchsClntNo", ret[0]);
        ds_ord.setCellData(rowIdx, "pchsClntNm", ret[1]);
        ds_ord.setCellData(rowIdx, "chk", "1");    
    } else {
        ds_ord.setCellData(rowIdx, "pchsClntNo", "");
        ds_ord.setCellData(rowIdx, "pchsClntNm", "");
    }



};


//-------------------------------------------------------------------------
// 그리드1 공통팝업 중기 종류 callback
//-------------------------------------------------------------------------
scwin.udc_gridPopup_CallbackFunc2 = function(rtnList1) {
    let rowIdx = gr_orderEachUnityPurchaseList.getFocusedRowIndex();

    if(rtnList1 != null & rtnList1[0] != "N/A"){
        ds_ord.setCellData(rowIdx, "vehclNo", rtnList1[1]);
        ds_ord.setCellData(rowIdx, "eqCd", rtnList1[2]);
        ds_ord.setCellData(rowIdx, "copCoClntNo", rtnList1[3]);
        ds_ord.setCellData(rowIdx, "copCoClntNm", rtnList1[4]);
        ds_ord.setCellData(rowIdx, "pchsClntNo", rtnList1[3]);
        ds_ord.setCellData(rowIdx, "pchsClntNm", rtnList1[4]);

    } else {
        ds_ord.setCellData(rowIdx, "vehclNo", "");
        ds_ord.setCellData(rowIdx, "eqCd", "");
        ds_ord.setCellData(rowIdx, "copCoClntNo", "");
        ds_ord.setCellData(rowIdx, "copCoClntNm", "");
        ds_ord.setCellData(rowIdx, "pchsClntNo", "");
        ds_ord.setCellData(rowIdx, "pchsClntNm", "");
    }
}


//---------------------------------------------------------
//조회조건 Clear
//---------------------------------------------------------
scwin.btn_init_onClick = function() {   	
    $c.gus.cfInitObjects(tbl_cndArea,null);
}




//---------------------------------------------------------
// 저장 (오더별매입현황) / f_save()
//---------------------------------------------------------
scwin.btn_saveSell_onClick = async function (e) {
    if(await $c.win.confirm(MSG_CM_CRM_001)){ //저장하시겠습니까?

        if(ds_ord.getModifiedIndex().length > 0){    
            let checkedCnt = 0;
            for(let i=0; i < ds_ord.getTotalRow(); i++){
                if(ds_ord.getCellData(i, "chk") == "T"){
                    checkedCnt++;
                    break;
                }
            }

            for (i=0; i < ds_ord.getTotalRow() ; i++) {

                if(ds_ord.getCellData(i, "chk") == "T" && ds_ord.getCellData(i, "vehclNo") == "")
                {
                    $c.win.alert((i+1) + "번째 데이타의 차량번호를 입력하십시오.");
                    return;
                }
                if(ds_ord.getCellData(i, "chk") == "T" && ds_ord.getCellData(i, "pchsClntNo") == "")
                {
                    $c.win.alert((i+1) + "번째 데이타의 매입거래처를 입력하십시오.");
                    return;
                }
                if(ds_ord.getCellData(i, "chk") == "T" && ds_ord.getCellData(i, "copCoClntNo") == "")
                {
                    $c.win.alert((i+1) + "번째 데이타의 협력업체를 입력하십시오.");
                    return;
                }
            }

            if(checkedCnt == 0){
                $c.win.alert("체크된 데이터가 없습니다.");
                return false;
            }    
            if($c.gus.cfValidate([gr_orderEachUnityPurchaseList]))
            {
                $c.sbm.execute(sbm_savePchsInfo); 
            }

        }else{
            $c.win.alert($c.data.getMessage(MSG_CM_ERR_001,"통합매입일괄수정")); //@은(는) 변경된 사항이 없습니다.
        }  
    }


};


//---------------------------------------------------------
// 저장 완료시
//---------------------------------------------------------
scwin.sbm_savePchsInfo_submitDone = function (e) {
    // $c.win.alert(MSG_CM_INF_001);    
    // $c.sbm.execute(sbm_queryConditionDTO);
    scwin.btn_retrieve_onClick();

};


//---------------------------------------------------------
// 저장2 (매입관리 그리드) f_save2
//---------------------------------------------------------
scwin.btn_savePchs_onClick = async function (e) {
    if(await $c.win.confirm(MSG_CM_CRM_001)){ //저장하시겠습니까?
        if (!scwin.f_setDsPchsUpdateRsn()) return;

        if(ds_pchsInfo.getModifiedIndex().length > 0){		
            if($c.gus.cfValidate([gr_pchsInfo])){
                if(!scwin.f_validatePchsInfo()) return;
                    $c.sbm.execute(sbm_savePchsInfo1);
                }
        }else{
            $c.win.alert($c.data.getMessage(MSG_CM_ERR_001,"통합매입조정")); //@은(는) 변경된 사항이 없습니다.
        }  
    }
};


scwin.f_setDsPchsUpdateRsn = function() {
    if(acb_pchsMainMainPattern.getValue() == "" || acb_pchsMainMainPattern.getValue() == null){ 
        $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "수정(삭제)사유")); //@은(는) 필수 입력 항목입니다
        acb_pchsMainMainPattern.focus();
        return false;
    }


    dma_updateRsnInfo.set("sellMainMainPattern1" , acb_pchsMainMainPattern.getValue());
    ds_pchsInfo.setCellData(0, "pchsMainMainRsn" , "");

    return true;

}

//---------------------------------------------------------
//validation 체크 (통합매입 수정및 신규 정보)
//---------------------------------------------------------
scwin.f_validatePchsInfo = function() {

    let validExp = "";
        for(i = 0; i < ds_pchsInfo.getRowCount(); i++ ){

            if(ds_pchsInfo.getRowStatus(i) == "C" || ds_pchsInfo.getRowStatus(i) == "U"){ //행추가 및 수정 상태인 경우 체크
                if( $c.gus.cfIsNull(ds_pchsInfo.getCellData(i, "selpchItemNm")) ){ 
                    $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "매입항목 ")); //@은(는) 필수 입력 항목입니다
                    return false;
                }
                if( $c.gus.cfIsNull(ds_pchsInfo.getCellData(i, "pchsGoodsPatternCd")) ){ 
                    $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "매입품목유형 ")); //@은(는) 필수 입력 항목입니다
                    return false;
                }
                if( $c.gus.cfIsNull(ds_pchsInfo.getCellData(i, "unitCd")) ){ 
                    $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "단위 ")); //@은(는) 필수 입력 항목입니다
                    return false;
                }
                if( $c.gus.cfIsNull(ds_pchsInfo.getCellData(i, "vol")) ){ 
                    $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "수량 ")); //@은(는) 필수 입력 항목입니다
                    return false;
                }
                if( $c.gus.cfIsNull(ds_pchsInfo.getCellData(i, "pchsUpr")) ){ 
                    $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "단가 ")); //@은(는) 필수 입력 항목입니다
                    return false;
                }
                if( $c.gus.cfIsNull(ds_pchsInfo.getCellData(i, "pchsAmt")) ){ 
                    $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "금액 ")); //@은(는) 필수 입력 항목입니다
                    return false;
                }
                if( $c.gus.cfIsNull(ds_pchsInfo.getCellData(i, "vat")) ){ 
                    $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "부가세 ")); //@은(는) 필수 입력 항목입니다
                    return false;
                }
                if( $c.gus.cfIsNull(ds_pchsInfo.getCellData(i, "pchsClntNm")) ){ 
                    $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "매입거래처 ")); //@은(는) 필수 입력 항목입니다
                    return false;
                }
                if( $c.gus.cfIsNull(ds_pchsInfo.getCellData(i, "copCoClntNm")) ){ 
                    $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "협력업체 ")); //@은(는) 필수 입력 항목입니다
                    return false;
                }
                if( $c.gus.cfIsNull(ds_pchsInfo.getCellData(i, "rsltsStdDt")) ){ 
                    $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "실적일 ")); //@은(는) 필수 입력 항목입니다
                    return false;
                }
                if( $c.gus.cfIsNull(ds_pchsInfo.getCellData(i, "bizDomNm")) ){ 
                    $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "사업영역 ")); //@은(는) 필수 입력 항목입니다
                    return false;
                }
                if( $c.gus.cfIsNull(ds_pchsInfo.getCellData(i, "pchsDeptNm")) ){ 
                    $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "부서 ")); //@은(는) 필수 입력 항목입니다
                    return false;
                }
                ds_pchsInfo.setCellData(i, "pchsMainMainPattern",acb_pchsMainMainPattern.getValue());
                ds_pchsInfo.setCellData(i, "pchsMainMainRsn", "");

            }
        }
    return true;
}



