//----------------------------------------------------------------------------------
// 끝전 처리
//----------------------------------------------------------------------------------
scwin.f_AmtSet = function(dsObj, row, colid, sellPchGubun) {
    var clntColumn = "";
    var itemColumn = "";
    var goodsCdColumn = "";
    var amtColumn = "";
    var unitColumn = "";


    if(sellPchGubun == "PCHS"){
        clntColumn = "pchsClntNo";
        itemColumn = "selpchItemCd";  //매입항목으로 수정  ( 2007.05.15 수정 ) 
        goodsCdColumn = "commCd";
        amtColumn = "pchsAmt";
        unitColumn = "unitCd";
    } else {
        clntColumn = "bilgClntNo";
        itemColumn = "sellItemCd";
        goodsCdColumn = "commCd";
        amtColumn = "sellAmt";
        unitColumn = "sellUnitCd";
    }

    // dma_volAmtSub

    //끝전처리 로직
    dma_volAmtSub.set("clntNo", dsObj.getCellData(row,clntColumn));
    dma_volAmtSub.set("selpchItemCd", dsObj.getCellData(row,itemColumn));
    dma_volAmtSub.set("goodsCd", dsObj.getCellData(row,goodsCdColumn));
    dma_volAmtSub.set("volAmtGubun", "AMT");
    dma_volAmtSub.set("resultAmt", dsObj.getCellData(row,amtColumn));
    dma_volAmtSub.set("weightUnitClsCd", dsObj.getCellData(row,unitColumn));

    $c.sbm.execute(sbm_volAmtSub);


}

scwin.ds_volAmtSub_ondataload = function () {
    ds_pchsInfo.setCellData(gr_pchsInfo.getFocusedRowIndex(), "pchsAmt", ds_volAmtSub.getCellData(0,"resultAmt"));

};

//-------------------------------------------------------------------------
// 매입그리드 데이터 편집 입장
//------------------------------------------------------------------------- 
scwin.gr_pchsInfo_onbeforeedit = function (rowIndex, columnIndex, value) {
    scwin.olddata = value;


};


//-------------------------------------------------------------------------
// 매입그리드 데이터 변경시
//------------------------------------------------------------------------- 
scwin.gr_pchsInfo_onafteredit = function (rowIndex, columnIndex, value) {
    let colid = gr_pchsInfo.getColumnID(columnIndex);

    if(scwin.olddata == value) {
        return;
    }

    switch(colid) {

        case "pchsSeq":
            if(value == "") {
                ds_pchsInfo.setCellData(rowIndex,"pchsSeq", 0);
            }
        break;

        case "pchsAmt":
            ds_pchsInfo.setCellData(rowIndex,"vat", Math.round(ds_pchsInfo.getCellData(rowIndex,colid) * 0.1));
        break;

        case "vol":
            if(value == "") {
                ds_pchsInfo.setCellData(rowIndex, colid, 0.000);
            }

            ds_pchsInfo.setCellData(rowIndex,"pchsAmt", ds_pchsInfo.getCellData(rowIndex,colid) * ds_pchsInfo.getCellData(rowIndex,"pchsUpr"));
            ds_pchsInfo.setCellData(rowIndex,"vat", Math.round(ds_pchsInfo.getCellData(rowIndex,"pchsAmt") * 0.1));
            scwin.f_AmtSet(ds_pchsInfo, rowIndex, "pchsAmt", "PCHS");
            break;
        case "pchsUpr":
            ds_pchsInfo.setCellData(rowIndex,"pchsAmt", ds_pchsInfo.getCellData(rowIndex,colid) * ds_pchsInfo.getCellData(rowIndex,"vol"));

            ds_pchsInfo.setCellData(rowIndex,"vat", Math.round(ds_pchsInfo.getCellData(rowIndex,"pchsAmt") * 0.1));
            scwin.f_AmtSet(ds_pchsInfo, rowIndex, "pchsAmt", "PCHS");
            break;
        default:
            break;
    }


};


scwin.ds_pchsInfo_ondataload = function () {
    gr_pchsInfo.setFocusedCell(0, 0);
};


scwin.gr_pchsInfo_oncellclick = function (rowIndex, columnIndex, columnId) {
    scwin.oldCol = columnId;


};
